import { readFileSync, writeFileSync } from "node:fs";
import { resolve } from "node:path";

const root = resolve(import.meta.dirname, "..");
const files = [
  "protocols.js",
  "metrics.js",
  "session-store.js",
  "ui-state.js",
  "ble.js",
  "app.js",
];

function stripModuleSyntax(source, filename) {
  const output = [];
  let skippingImport = false;

  for (const line of source.split(/\r?\n/)) {
    if (skippingImport) {
      if (line.includes(";")) skippingImport = false;
      continue;
    }

    if (/^\s*import\b/.test(line)) {
      if (!line.includes(";")) skippingImport = true;
      continue;
    }

    output.push(line.replace(/^export\s+(?=(const|let|var|function|class)\b)/, ""));
  }

  return `\n// ---- ${filename} ----\n${output.join("\n")}\n`;
}

const banner = `// Generated by tools/build-browser-bundle.mjs.
// The source modules remain the testable implementation; this bundle lets index.html run from file:// and GitHub Pages.
`;

const bundled = banner + files
  .map((file) => stripModuleSyntax(readFileSync(resolve(root, file), "utf8"), file))
  .join("\n");

writeFileSync(resolve(root, "app.bundle.js"), bundled, "utf8");
